// ─── Supabase Client ───
const SUPABASE_URL="https://chpshustwroyoueursha.supabase.co";
const SUPABASE_KEY="sb_publishable_dKhwUOqNtIWmdwRqrL5jIw_ZX5Ebzoc";
const sbHeaders={"apikey":SUPABASE_KEY,"Authorization":`Bearer ${SUPABASE_KEY}`,"Content-Type":"application/json","Prefer":"return=representation"};
const sb={
  async get(table){try{const r=await fetch(`${SUPABASE_URL}/rest/v1/${table}?select=*&order=created_at.desc`,{headers:sbHeaders});if(!r.ok)throw new Error(r.statusText);return await r.json();}catch(e){console.error(`[sb.get] ${table}:`,e);return[];}},
  async insert(table,data){try{const r=await fetch(`${SUPABASE_URL}/rest/v1/${table}`,{method:"POST",headers:sbHeaders,body:JSON.stringify(data)});if(!r.ok)throw new Error(r.statusText);return await r.json();}catch(e){console.error(`[sb.insert] ${table}:`,e);return null;}},
  async update(table,id,data){try{const r=await fetch(`${SUPABASE_URL}/rest/v1/${table}?id=eq.${id}`,{method:"PATCH",headers:{...sbHeaders,"Prefer":"return=representation"},body:JSON.stringify(data)});if(!r.ok)throw new Error(r.statusText);return await r.json();}catch(e){console.error(`[sb.update] ${table}:`,e);return null;}},
  async remove(table,id){try{await fetch(`${SUPABASE_URL}/rest/v1/${table}?id=eq.${id}`,{method:"DELETE",headers:sbHeaders});return true;}catch(e){console.error(`[sb.delete] ${table}:`,e);return false;}}
};

